## NuGet Packages

```
dotnet add package OpenTelemetry.Extensions.Hosting
dotnet add package OpenTelemetry.Exporter.OpenTelemetryProtocol
dotnet add package OpenTelemetry.Instrumentation.AspNetCore
dotnet add package OpenTelemetry.Instrumentation.Http
```

## Program.cs

```csharp
using OpenTelemetry.Logs;
using OpenTelemetry.Metrics;
using OpenTelemetry.Resources;
using OpenTelemetry.Trace;

var builder = WebApplication.CreateBuilder(args);

var serviceName = "MyApp";
var otlpEndpoint = builder.Configuration["OTEL_EXPORTER_OTLP_ENDPOINT"]
                   ?? "http://localhost:4317";

// Shared resource for all signals
var resource = ResourceBuilder.CreateDefault()
    .AddService(serviceName);

// --- Traces ---
builder.Services.AddOpenTelemetry()
    .ConfigureResource(r => r.AddService(serviceName))
    .WithTracing(tracing =>
    {
        tracing
            .AddAspNetCoreInstrumentation()
            .AddHttpClientInstrumentation()
            .AddOtlpExporter(o => o.Endpoint = new Uri(otlpEndpoint));
    })
    // --- Metrics ---
    .WithMetrics(metrics =>
    {
        metrics
            .AddAspNetCoreInstrumentation()
            .AddHttpClientInstrumentation()
            .AddRuntimeInstrumentation()
            .AddOtlpExporter(o => o.Endpoint = new Uri(otlpEndpoint));
    });

// --- Logs ---
builder.Logging.AddOpenTelemetry(logging =>
{
    logging.SetResourceBuilder(resource);
    logging.IncludeFormattedMessage = true;
    logging.IncludeScopes = true;
    logging.AddOtlpExporter(o => o.Endpoint = new Uri(otlpEndpoint));
});

var app = builder.Build();
app.MapGet("/", () => "Hello World");
app.Run();
```

**Key points:**

- **Traces & Metrics** use the fluent `AddOpenTelemetry()` builder on `IServiceCollection`.
- **Logs** are configured separately via `builder.Logging.AddOpenTelemetry()` since they go through `ILoggingBuilder`.
- The default OTLP transport is **gRPC on port 4317**. For HTTP/protobuf, use port `4318` and set `o.Protocol = OtlpExportProtocol.HttpProtobuf`.
- For runtime metrics (`GC`, `ThreadPool`), add `OpenTelemetry.Instrumentation.Runtime` as an additional package.
- Set `OTEL_EXPORTER_OTLP_ENDPOINT` env var to override the collector address at deploy time.
